import { useEffect, useRef } from "react";

/**
 * Hero — TRANSLATE approach (matches reference exactly)
 *
 * The WHOLE ROW [Juan | Card | Mora] moves left/right as one unit.
 * Juan exits the LEFT edge of the screen.
 * Mora exits the RIGHT edge of the screen.
 * NO clipping, NO squeezing — pure translation.
 *
 * Math:
 *   SVG height: 15.5vw → Juan=37.9vw, Mora=46.3vw (from 570/233 and 696/233 ratios)
 *   Card: 25vw  (measured from reference frame: 320px / 1280px)
 *   Total row: 109.2vw  (wider than viewport by 9.2vw)
 *
 *   rowLeft = cursorFrac × 100 − card/2 − juanWidth
 *   At cursor 50%: rowLeft ≈ 0 → Juan starts at left edge ✓
 */

const PROJECTS = [
  { src: "https://images.unsplash.com/photo-1561070791-2526d30994b5?w=800&q=80", label: "Alena Branding" },
  { src: "https://images.unsplash.com/photo-1635322966219-b75ed372eb01?w=800&q=80", label: "App Design" },
  { src: "https://images.unsplash.com/photo-1547658719-da2b51169166?w=800&q=80", label: "Web Design" },
  { src: "https://images.unsplash.com/photo-1499951360447-b19be8fe80f5?w=800&q=80", label: "TopTrader" },
  { src: "https://images.unsplash.com/photo-1467232004584-a241de8bcf5d?w=800&q=80", label: "Google Project" },
];

// Sizing constants — derived from reference measurements + SVG viewBox ratios
const SVG_H_VW  = 15.5;                       // letter height in vw
const JUAN_VW   = (570 / 233) * SVG_H_VW;     // ≈ 37.9vw
const CARD_VW   = 25;                          // measured from reference frame
const MORA_VW   = (696 / 233) * SVG_H_VW;     // ≈ 46.3vw

// Actual Goga font paths extracted from juanmora.co Lottie SVG
